'use strict';
// dayjs: date/time manipulation — no cryptography

const UNITS = ['year', 'month', 'day', 'hour', 'minute', 'second', 'millisecond'];

class Dayjs {
  constructor(date) {
    this._date = date instanceof Date ? date : new Date(date || Date.now());
  }

  format(template) {
    const d = this._date;
    return template
      .replace('YYYY', d.getFullYear())
      .replace('MM', String(d.getMonth() + 1).padStart(2, '0'))
      .replace('DD', String(d.getDate()).padStart(2, '0'))
      .replace('HH', String(d.getHours()).padStart(2, '0'))
      .replace('mm', String(d.getMinutes()).padStart(2, '0'))
      .replace('ss', String(d.getSeconds()).padStart(2, '0'));
  }

  add(value, unit) {
    const d = new Date(this._date);
    if (unit === 'day') d.setDate(d.getDate() + value);
    if (unit === 'month') d.setMonth(d.getMonth() + value);
    return new Dayjs(d);
  }

  toDate() { return new Date(this._date); }
  valueOf() { return this._date.getTime(); }
}

module.exports = (date) => new Dayjs(date);
